attribute romstyle : string;
attribute romstyle of COS_LUT : constant is "M20K";
attribute romstyle of SIN_LUT : constant is "M20K";


function twiddle(x : integer; m : std_logic; N : integer) return complex_S16;
function bit_reverse(x : integer; logN : integer) return integer;
function add_c32(x : complex_S32; y : complex_S32) return complex_S32;
function sub_c32(x : complex_S32; y : complex_S32) return complex_S32;
function multc(x : complex_S32; tw : complex_S16) return complex_S32;
function shift_right_c32(x : complex_S32; s : integer) return complex_S32;
function saturate_signed(x : signed; s : integer) return signed;

end package fft_pkg;

package body fft_pkg is

function twiddle(x : integer; m : std_logic; N : integer) return complex_S16 is
	variable y : complex_S16;
	variable w : integer := x*(LUT_SIZE/N);
begin
	y.re := signed(COS_LUT(w));
	if (m = '0') then
		y.im := signed(SIN_LUT(w));
	else
		y.im := -signed(SIN_LUT(w));
	end if;
	return y;
end twiddle;

function bit_reverse(x : integer; logN : integer) return integer is
    variable x_u : unsigned(logN-1 downto 0);
    variable y_u : unsigned(logN-1 downto 0);
begin
    x_u := to_unsigned(x, logN);

    for i in 0 to logN-1 loop
        y_u(i) := x_u(logN - 1 - i);
    end loop;

    return to_integer(y_u);
end bit_reverse;

function add_c32(x : complex_S32; y : complex_S32) return complex_S32 is
	variable u : complex_S32;
begin
	u.re := saturate_signed(resize(x.re,33) + resize(y.re,33),32);
	u.im := saturate_signed(resize(x.im,33) + resize(y.im,33),32);

		return u;
end add_c32;

function sub_c32(x : complex_S32; y : complex_S32) return complex_S32 is
	variable u : complex_S32;
begin
	u.re := saturate_signed(resize(x.re,33) - resize(y.re,33),32);
	u.im := saturate_signed(resize(x.im,33) - resize(y.im,33),32);
		return u;
end sub_c32;

function multc(x : complex_S32; tw : complex_S16) return complex_S32 is
	variable u_re : S48;
	variable u_im : S48;
	variable v_re : S48;
	variable v_im : S48;
	variable re_wide : signed(48 downto 0);
	variable im_wide : signed(48 downto 0);
	variable y : complex_S32;
begin
	u_re := x.re * tw.re;
	u_im := x.re * tw.im;
	v_re := x.im * tw.im;
	v_im := x.im * tw.re;
	
	
   re_wide := resize(u_re, 49) - resize(v_re, 49);
   im_wide := resize(u_im, 49) + resize(v_im, 49);

	
	y.re := saturate_signed(shift_right(re_wide,15),32);
	y.im := saturate_signed(shift_right(im_wide,15),32);
	
	return y;
end multc;

function shift_right_c32(x : complex_S32; s : integer) return complex_S32 is
	variable u : complex_S32;
begin
	u.re := shift_right(x.re,s);
	u.im := shift_right(x.im,s);
	return u;
end shift_right_c32;

function saturate_signed(x : signed; s : integer) return signed is
	constant MAX : signed(s-1 downto 0) := (s-1 => '0', others => '1');
	constant MIN : signed(s-1 downto 0) := (s-1 => '1', others => '0');
begin
	if (x > resize(MAX,x'length)) then
		return MAX;
	elsif (x < resize(MIN,x'length)) then
		return MIN;
	else
		return resize(x,s);
	end if;
end saturate_signed;
	

end fft_pkg;
